//alert ('@@@');	}	function SetLastVisit (name, value) 	{		var newVisitDate = new Date();		var expDate = new Date (); 		var numVisits = 0;			// The expDate is the date when the cookie should			// expire, we will keep it for a year		expDate.setTime( expDate.getTime() + (1 * 365 * 24 * 60 * 60 * 1000) ); 			// Info about last visit		if (GetCookie (cookieVisitID) != null)			gLastVisit = GetCookie (cookieVisitID);		else			gLastVisit = "";		if (GetCookie (cookieNumVisitID) != null)			gNumVisits = GetCookie (cookieNumVisitID);			else			gNumVisits = 0;			// Use eval() to convert a string to a number		numVisits = eval(gNumVisits) +1;				// Store info about this visit		SetCookie( cookieVisitID, 	newVisitDate, expDate); 		SetCookie( cookieNumVisitID, numVisits, expDate); }function textCounter(field,cntfield,maxlimit) {	if (field.value.length > maxlimit) 	{		// if too long...trim it!		field.value = field.value.substring(0, maxlimit);		// otherwise, update 'characters left' counter	}	else		{cntfield.value = maxlimit - field.value.length;}}    function getCookieVal (offset) {      var endstr = document.cookie.indexOf (";", offset);      if (endstr == -1)        endstr = document.cookie.length;      return unescape(document.cookie.substring(offset, endstr));    }    function GetCookie (name) {      var arg = name + "=";      var alen = arg.length;      var clen = document.cookie.length;      var i = 0;      while (i < clen) {        var j = i + alen;        if (document.cookie.substring(i, j) == arg)          return getCookieVal (j);        i = document.cookie.indexOf(" ", i) + 1;        if (i == 0) break;       }      return null;    }    function SetCookie (name, value) {      var argv = SetCookie.arguments;      var argc = SetCookie.arguments.length;      var expires = (argc > 2) ? argv[2] : null;      var path = (argc > 3) ? argv[3] : null;      var domain = (argc > 4) ? argv[4] : null;      var secure = (argc > 5) ? argv[5] : false;      document.cookie = name + "=" + escape (value) +        ((expires == null) ? "" : ("; expires=" + expires.toGMTString())) +        ((path == null) ? "" : ("; path=" + path)) +        ((domain == null) ? "" : ("; domain=" + domain)) +        ((secure == true) ? "; secure" : "");    }    function DeleteCookie (name) {      var exp = new Date();      exp.setTime (exp.getTime() - 1);  // This cookie is history      var cval = GetCookie (name);      document.cookie = name + "=" + cval + "; expires=" + exp.toGMTString();    }// --></SCRIPT></head> <body><table cellspacing="0" cellpadding="0" ><tr>				  <td height="12" class="kladblokkop">&nbsp;<img src="../pics/mensje.gif" alt="menselijk"  width="10" height="12"  > 		Kladblokje</td>			<td align="right"><a href="javascript:void(0);" onclick="window.close();" class="kladblokkop">[&#8722;]</a></td>		</tr></table><p align="right"><span class="kleineletters">de informatie die je hier opschrijft   wordt uit privacy overwegingen  pas opgeslagen op jouw eigen computer als je dat aangeeft </span>   <!--  Note1 -->  <a href="javascript:void(0);" id="note1_title" class="note" onclick="showNote('note1');">!</a> <span id="note1_body" class="notehidden"><br>	<div class="notebody" align="left">   <table class="notetitle" cellspacing="0" cellpadding="0">    <tr>       <td height="12">Toelichting : privacy</td>      <td align="right"><a href="javascript:void(0);" onclick="hideNote('note1');" class="notetitle" >[&#8722;]</a></td>    </tr>  </table>  <p>Hiervoor gebruiken we een 'cookie'<br>    dus dat moet wel 'AAN' staan<br>    in de 'preferences/instellingen<br>    van je browser...<br>    anders werkt dit niet.</p></div>	</span><p><span class="notehidden"></span></p><span class="notehidden"><noscript><p> *dit werkt alleen als javascript AAN staat* </p></noscript>	</span> <!-- / Note --></p>	<p>&nbsp;<img src="../pics/mensje.gif" alt="menselijk"  width="10"